mapper.delete:
/** CmmtSurveyAnswerDao.deleteList_surveyId */
delete from
	cmmt_survey_answer
where
	survey_id = #{surveyId}

mapper.insert:
/** CmmtSurveyAnswerDao.insertList */
insert into cmmt_survey_answer (
	 survey_id
	,question_id
	,answer_id
	,answer_no
	,answer_cn
) values

	(
		 #{item.surveyId}
		,#{item.questionId}
		,#{item.answerId}
		,#{item.answerNo}
		,#{item.answerCn}
	)
